530:     const flexibleRegexPattern = words.join('[\\s\\n\\r]*(?:<[^>]+>)*[\\s\\n\\r]*');
531:     
532:     // Regex patterns to match element tags completely to avoid leaving empty boxes on screen
533:     const leafRegex = new RegExp('<div\\s+class=["\']leaf-item["\'][^>]*>\\s*' + flexibleRegexPattern + '\\s*</div>', 'gi');
534:     const subBtnRegex = new RegExp('<(?:button|div)\\s+class=["\']sub-btn["\'][^>]*>\\s*(?:<i[^>]*>[^<]*</i>\\s*)*' + flexibleRegexPattern + '\\s*</(?:button|div)>', 'gi');
535:     const branchBtnRegex = new RegExp('<button\\s+class=["\']branch-btn["\'][^>]*>\\s*(?:<i[^>]*>[^<]*</i>\\s*)*' + flexibleRegexPattern + '\\s*</button>', 'gi');
536:     const rootBtnRegex = new RegExp('<button\\s+class=["\']root-btn["\'][^>]*>\\s*' + flexibleRegexPattern + '\\s*</button>', 'gi');
537:     const genericRegex = new RegExp(flexibleRegexPattern, 'gi');
538:     
539:     let updated = currentContent;
540:     let temp = updated.replace(leafRegex, '');
541:     if (temp.length < updated.length) {
542:       updated = temp;
543:     } else {
544:       temp = updated.replace(subBtnRegex, '');
545:       if (temp.length < updated.length) {
546:         updated = temp;
547:       } else {
548:         temp = updated.replace(branchBtnRegex, '');
549:         if (temp.length < updated.length) {
550:           updated = temp;
