552:           temp = updated.replace(rootBtnRegex, '');
553:           if (temp.length < updated.length) {
554:             updated = temp;
555:           } else {
556:             temp = updated.replace(genericRegex, '');
557:             if (temp.length < updated.length) {
558:               updated = temp;
559:             }
560:           }
561:         }
562:       }
563:     }
564:     
565:     if (updated !== currentContent) {
